import{_ as t,o as r,c as i,ae as a}from"./chunks/framework.BD9pLfSD.js";const h=JSON.parse('{"title":"Track C: Infrastructure, Observability & Receipts","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/tracks/track_c_infra_listener.md","filePath":"docs/plans/tracks/track_c_infra_listener.md"}'),o={name:"docs/plans/tracks/track_c_infra_listener.md"};function s(n,e,l,c,d,u){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="track-c-infrastructure-observability-receipts" tabindex="-1">Track C: Infrastructure, Observability &amp; Receipts <a class="header-anchor" href="#track-c-infrastructure-observability-receipts" aria-label="Permalink to &quot;Track C: Infrastructure, Observability &amp; Receipts&quot;">​</a></h1><p><strong>Branch Name:</strong> <code>feat/infra-receipts-listener</code><strong>Base Branch:</strong> <code>base-integration</code> (Consolidated)</p><h2 id="_1-objective" tabindex="-1">1. Objective <a class="header-anchor" href="#_1-objective" aria-label="Permalink to &quot;1. Objective&quot;">​</a></h2><p>To build the &quot;All-Seeing Eye&quot; (Backend) that makes sense of the fragmented privacy activities. It acts as the unifying indexer that listens to On-Chain events (ShadowWire, SilentSwap, Privacy Cash) and Off-Chain Webhooks (Starpay) to produce a coherent audit trail and generate Compressed Receipts.</p><h2 id="_2-core-components" tabindex="-1">2. Core Components <a class="header-anchor" href="#_2-core-components" aria-label="Permalink to &quot;2. Core Components&quot;">​</a></h2><h3 id="_2-1-the-unified-listener-mcp-server" tabindex="-1">2.1. The Unified Listener (MCP Server) <a class="header-anchor" href="#_2-1-the-unified-listener-mcp-server" aria-label="Permalink to &quot;2.1. The Unified Listener (MCP Server)&quot;">​</a></h3><p>The central backend service.</p><ul><li><strong>Path:</strong> <code>mcp/src/listener.ts</code></li><li><strong>Helius Integration:</strong> Uses Helius Webhooks/DAS to detect on-chain transfers.</li><li><strong>Starpay Webhooks:</strong> An Express/Fastify route to receive card transaction payloads.</li><li><strong>Logic:</strong> Normalizes all events into a standard <code>TransactionEvent</code> format.</li></ul><h3 id="_2-2-the-receipt-issuer-light-protocol" tabindex="-1">2.2. The Receipt Issuer (Light Protocol) <a class="header-anchor" href="#_2-2-the-receipt-issuer-light-protocol" aria-label="Permalink to &quot;2.2. The Receipt Issuer (Light Protocol)&quot;">​</a></h3><ul><li><strong>Path:</strong> <code>onchain/programs/xb77_receipts/</code></li><li><strong>Task:</strong> When the Listener confirms a payment (from ANY source), it invokes this program via CPI (or direct tx) to mint a <strong>Compressed Receipt</strong>.</li><li><strong>Importance:</strong> This unifies the accounting. A fiat payment via Starpay creates a ZK-compressed receipt on Solana just like a native transfer.</li></ul><h3 id="_2-3-observability-helius" tabindex="-1">2.3. Observability (Helius) <a class="header-anchor" href="#_2-3-observability-helius" aria-label="Permalink to &quot;2.3. Observability (Helius)&quot;">​</a></h3><ul><li><strong>Dashboard:</strong> Configure Helius to tag and monitor the specific addresses of our Stubs and Registry.</li><li><strong>Alerts:</strong> Set up notifications for high-value transfers (simulation of Range compliance alerts).</li></ul><h2 id="_3-integration-points" tabindex="-1">3. Integration Points <a class="header-anchor" href="#_3-integration-points" aria-label="Permalink to &quot;3. Integration Points&quot;">​</a></h2><h3 id="input-from-track-a-b" tabindex="-1">Input from Track A &amp; B <a class="header-anchor" href="#input-from-track-a-b" aria-label="Permalink to &quot;Input from Track A &amp; B&quot;">​</a></h3><ul><li>Tracks A &amp; B generate the noise (txs). Track C listens.</li><li><strong>Compliance Hook (Range):</strong> If implemented, this Track exposes an API endpoint <code>/check-compliance</code> that Track A calls before executing a tx.</li></ul><h3 id="output-to-track-b-hub" tabindex="-1">Output to Track B (Hub) <a class="header-anchor" href="#output-to-track-b-hub" aria-label="Permalink to &quot;Output to Track B (Hub)&quot;">​</a></h3><ul><li><strong>Unified History API:</strong> Exposes <code>GET /history</code> returning a mixed list of Crypto and Fiat operations.</li><li><strong>WebSocket:</strong> Pushes updates to the Hub UI.</li></ul><h2 id="_4-execution-plan" tabindex="-1">4. Execution Plan <a class="header-anchor" href="#_4-execution-plan" aria-label="Permalink to &quot;4. Execution Plan&quot;">​</a></h2><ul><li>[x] <strong>Receipts Program:</strong> Finish <code>xb77_receipts</code> (Record Receipt instruction).</li><li>[x] <strong>Helius Setup:</strong> Config script for Webhooks (<code>scripts/infra/setup_helius.ts</code>).</li><li>[x] <strong>Unified Listener:</strong> Implement HTTP endpoint for card events and Helius (<code>mcp/src/listener.ts</code>).</li><li>[x] <strong>Normalization Logic:</strong> &quot;If Starpay Event -&gt; Create Compressed Receipt&quot;.</li><li>[x] <strong>Persistence:</strong> Added <code>SQLiteReceiptStore</code> (Native Bun SQLite) for offline/local history.</li><li>[ ] <strong>History API:</strong> Simple endpoint for the Hub (Partially covered by <code>agent.receipts.list</code> tool).</li></ul><h2 id="_5-status-update-2026-01-23" tabindex="-1">5. Status Update (2026-01-23) <a class="header-anchor" href="#_5-status-update-2026-01-23" aria-label="Permalink to &quot;5. Status Update (2026-01-23)&quot;">​</a></h2><ul><li><strong>Completed:</strong><ul><li><code>xb77_receipts</code> program implemented with Light Protocol CPI.</li><li><code>mcp/src/listener.ts</code> service running on port 7002.</li><li>Webhook handling for Starpay and Helius.</li><li><strong>SQLite Persistence</strong>: Replaced in-memory store with <code>bun:sqlite</code> (<code>xb77_agent.db</code>).</li></ul></li><li><strong>Next Steps:</strong><ul><li>Integrate WebSocket for real-time Hub updates.</li><li>Add signature verification for production security.</li></ul></li></ul>',21)])])}const g=t(o,[["render",s]]);export{h as __pageData,g as default};
